#include <iostream>
using namespace std;

class BankAccount {
private:
    double balance;   // hidden
    string password;

    bool authenticate(string pwd) {
        return pwd == password;
    }

public:
    BankAccount(string pwd) : balance(0), password(pwd) {}

    void deposit(double amount) {
        if (amount > 0) balance += amount;
    }

    bool withdraw(double amount, string pwd) {
        if (authenticate(pwd) && amount <= balance) {
            balance -= amount;
            return true;
        }
        return false;
    }

    double getBalance(string pwd) {
        return authenticate(pwd) ? balance : -1;
    }
};

int main() {
    BankAccount acc("secret123");
    acc.deposit(1000);
    if (acc.withdraw(500, "secret123"))
        cout << "Withdrawn 500" << endl;
    cout << "Balance: " << acc.getBalance("secret123") << endl;
    return 0;
}

