#include <iostream>
using namespace std;

// Single inheritance: one base, one derived
class A { public: void a() { cout << "A"; } };
class B : public A { public: void b() { cout << "B"; } };

// Multiple inheritance: derived from multiple bases
class X { public: void x() { cout << "X"; } };
class Y { public: void y() { cout << "Y"; } };
class Z : public X, public Y { public: void z() { cout << "Z"; } };

// Multilevel: A -> B -> C
class Base { public: void base() { cout << "Base"; } };
class Intermediate : public Base { public: void inter() { cout << "Inter"; } };
class Derived : public Intermediate { public: void derived() { cout << "Derived"; } };

// Hierarchical: multiple derived from one base
class Shape { public: virtual void draw() = 0; };
class Circle : public Shape { void draw() override { cout << "Circle"; } };
class Square : public Shape { void draw() override { cout << "Square"; } };

int main() {
    B b; b.a(); b.b(); cout << endl;
    Z z; z.x(); z.y(); z.z(); cout << endl;
    Derived d; d.base(); d.inter(); d.derived(); cout << endl;
    return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
    int pub = 1;
protected:
    int prot = 2;
private:
    int priv = 3;
};

// public inheritance
class PubDerived : public Base {
    // pub remains public, prot remains protected, priv inaccessible
    void func() {
        cout << pub << " " << prot << endl; // priv not accessible
    }
};

// protected inheritance
class ProtDerived : protected Base {
    // pub and prot become protected
};

// private inheritance
class PrivDerived : private Base {
    // pub and prot become private
};

int main() {
    PubDerived pd;
    cout << pd.pub << endl;  // OK, public
    // cout << pd.prot; // ERROR: protected
    return 0;
}

