#include <iostream>
using namespace std;

class Animal {
public:
    virtual void speak() {   // virtual allows override
        cout << "Animal sound" << endl;
    }
    virtual ~Animal() {}     // virtual destructor
};

class Dog : public Animal {
public:
    void speak() override {  // override keyword optional but good
        cout << "Woof!" << endl;
    }
};

class Cat : public Animal {
public:
    void speak() override {
        cout << "Meow!" << endl;
    }
};

int main() {
    Animal* ptr;
    Dog d;
    Cat c;

    ptr = &d;
    ptr->speak();   // Woof!
    ptr = &c;
    ptr->speak();   // Meow!

    return 0;
}

#include <iostream>
using namespace std;

// Abstract class (has pure virtual function)
class Shape {
public:
    virtual double area() = 0;  // pure virtual
    virtual void display() {
        cout << "Area: " << area() << endl;
    }
    virtual ~Shape() {}
};

class Rectangle : public Shape {
private:
    double w, h;
public:
    Rectangle(double width, double height) : w(width), h(height) {}
    double area() override {
        return w * h;
    }
};

class Circle : public Shape {
private:
    double r;
public:
    Circle(double radius) : r(radius) {}
    double area() override {
        return 3.14159 * r * r;
    }
};

int main() {
    // Shape s; // ERROR: abstract class cannot be instantiated
    Shape* shapes[] = {new Rectangle(5, 10), new Circle(7)};
    for (auto s : shapes) {
        s->display();
        delete s;
    }
    return 0;
}
